#!/bin/bash`n# bin/hostname.sh - 生成主机名`n`nset -e`n`nSCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"`nPROJECT_DIR="$(cd "$SCRIPT_DIR/.." && pwd)"`n`nsource "$PROJECT_DIR/lib/output.sh"`nsource "$PROJECT_DIR/config/region-codes.conf"`n`nCOUNTRY="${COUNTRY:-us}"`nREGION="${REGION:-unknown}"`nMERCHANT="${MERCHANT:-unknown}"`nNET_TYPE="${NET_TYPE:-unknown}"`n`nmain() {`n    local region_code="${REGION_CODES[$REGION]:-${REGION:0:3}}"`n    region_code=$(echo "$region_code" | tr '[:upper:]' '[:lower:]')`n    COUNTRY=$(echo "$COUNTRY" | tr '[:upper:]' '[:lower:]')`n    `n    local rand8=$(head /dev/urandom 2>/dev/null | tr -dc 'a-z0-9' | head -c 8)`n    `n    local hostname="${COUNTRY}-${region_code}-${NET_TYPE}-${MERCHANT}-${rand8}"`n    `n    echo "HOSTNAME=$hostname"`n}`n`nmain "$@"`n